const body = $json.body || $json;
const events = body.events || [];
const now = new Date();
const dt = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Bangkok' }));
const pad = n => String(n).padStart(2, '0');
const today = `${dt.getFullYear()}-${pad(dt.getMonth()+1)}-${pad(dt.getDate())}`;
const tmrDt = new Date(dt.getTime() + 86400000);
const tmr = `${tmrDt.getFullYear()}-${pad(tmrDt.getMonth()+1)}-${pad(tmrDt.getDate())}`;
const month = `${dt.getFullYear()}-${pad(dt.getMonth()+1)}`;
const nextMonthDt = new Date(dt.getFullYear(), dt.getMonth()+1, 1);
const nextMonth = `${nextMonthDt.getFullYear()}-${pad(nextMonthDt.getMonth()+1)}`;

return events
  .filter(e => e.type === 'message' && e.message?.type === 'text')
  .map(e => ({
    json: {
      replyToken: e.replyToken,
      userId: e.source.userId,
      userMessage: e.message.text,
      today, tmr, month, nextMonth,
      year: dt.getFullYear(),
      beYear: dt.getFullYear() + 543
    }
  }));

