const raw = $json;
const prev = $('Parse LINE Event').first().json;

let aiText = raw.output || raw.text || JSON.stringify(raw);

let p = { intent: 'chat' };
try {
  let t = String(aiText).replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
  const i = t.indexOf('{');
  if (i !== -1) p = JSON.parse(t.substring(i).replace(/,\s*([\}\]])/g, '$1'));
} catch (e) {}

const validIntents = ['create', 'list', 'update', 'delete', 'holiday', 'chat'];
if (!validIntents.includes(p.intent)) p.intent = 'chat';

const msg = String(prev.userMessage || '').toLowerCase();

// แก้ปี พ.ศ. ที่ AI อาจคืนมาเป็น 2569-xx-xx ให้เป็น ค.ศ. 2026-xx-xx
function convertBE(value) {
  if (!value || typeof value !== 'string') return value || '';
  return value.replace(/^(25\d{2})(-\d{2}(?:-\d{2})?)(.*)$/, (_, y, rest, tail) => `${Number(y) - 543}${rest}${tail}`);
}
p.queryDate = convertBE(p.queryDate);
p.startDateTime = convertBE(p.startDateTime);
p.endDateTime = convertBE(p.endDateTime);

// Safety net for date keywords
if (msg.includes('เดือนนี้') && p.queryDate !== prev.month) {
  p.queryDate = prev.month;
}
if (msg.includes('เดือนหน้า') && p.queryDate !== prev.nextMonth) {
  p.queryDate = prev.nextMonth;
}
if (msg.includes('พรุ่งนี้') && p.queryDate === prev.today) {
  p.queryDate = prev.tmr;
}
if (msg.includes('วันนี้') && p.queryDate === prev.tmr) {
  p.queryDate = prev.today;
}

// Safety net for holiday intent
const holidayWords = ['วันหยุด', 'หยุดไหม', 'หยุดหรือเปล่า', 'หยุดมั้ย', 'วันหยุดราชการ', 'นักขัตฤกษ์'];
if (holidayWords.some(w => msg.includes(w))) {
  p.intent = 'holiday';
  if (!p.queryDate) p.queryDate = prev.today;
}

// ถ้าถามรายการ แต่มีคำว่า "มีอะไร" ยังคง list ตามเดิม
// Build queryStartDate / queryEndDate (รองรับทั้ง YYYY-MM-DD และ YYYY-MM)
let queryStartDate = '', queryEndDate = '';
let isMonthQuery = false;
if (p.queryDate) {
  if (/^\d{4}-\d{2}-\d{2}$/.test(p.queryDate)) {
    // วันเดียว: ใช้ช่วง 00:00 ถึงวันถัดไป 00:00 เพื่อรองรับ all-day event ของ Google Calendar
    queryStartDate = `${p.queryDate}T00:00:00+07:00`;
    const [yr, mo, da] = p.queryDate.split('-').map(Number);
    const next = new Date(yr, mo - 1, da + 1);
    const pad = n => String(n).padStart(2, '0');
    queryEndDate = `${next.getFullYear()}-${pad(next.getMonth()+1)}-${pad(next.getDate())}T00:00:00+07:00`;
  } else if (/^\d{4}-\d{2}$/.test(p.queryDate)) {
    // ทั้งเดือน
    const [yr, mo] = p.queryDate.split('-').map(Number);
    const pad = n => String(n).padStart(2, '0');
    const nextMonth = new Date(yr, mo, 1);
    queryStartDate = `${p.queryDate}-01T00:00:00+07:00`;
    queryEndDate = `${nextMonth.getFullYear()}-${pad(nextMonth.getMonth()+1)}-${pad(nextMonth.getDate())}T00:00:00+07:00`;
    isMonthQuery = true;
  }
}

return [{ json: {
  ...prev,
  intent: p.intent,
  title: p.title || '',
  originalTitle: p.originalTitle || '',
  startDateTime: p.startDateTime || '',
  endDateTime: p.endDateTime || '',
  queryDate: p.queryDate || '',
  queryStartDate, queryEndDate, isMonthQuery,
  changeTime: p.changeTime === true,
  changeTitle: p.changeTitle === true
}}];

const p = $('Extract Parser JSON').first().json;
const e = $json;
let timeStr = '';
if (e.start?.dateTime) {
  timeStr = new Date(e.start.dateTime).toLocaleString('th-TH', { dateStyle: 'medium', timeStyle: 'short', timeZone: 'Asia/Bangkok' });
}
return [{ json: {
  actionResult: `สร้างกิจกรรม "${e.summary || p.title}" เวลา ${timeStr} เรียบร้อย`,
  replyToken: p.replyToken,
  intent: 'create'
}}];

const events = $input.all().map(i => i.json).filter(j => j && j.id);
const p = $('Extract Parser JSON').first().json;
const tag = `[LINE:${p.userId}]`;
const filtered = events.filter(e => String(e.description || '').includes(tag));

const isMonth = !!p.isMonthQuery;
const label = isMonth ? 'เดือน' : 'วันที่';

let text;
if (filtered.length === 0) {
  text = `ไม่พบกิจกรรม${label} ${p.queryDate}`;
} else {
  const lines = filtered.map((e, i) => {
    const s = e.start?.dateTime || e.start?.date;
    if (!s) return `${i+1}. (ไม่ทราบเวลา) — ${e.summary || '(ไม่มีหัวข้อ)'}`;
    const d = new Date(s);
    if (isMonth) {
      const datePart = d.toLocaleDateString('th-TH', { day: '2-digit', month: 'short', timeZone: 'Asia/Bangkok' });
      const timePart = e.start.dateTime ? d.toLocaleTimeString('th-TH', { hour: '2-digit', minute: '2-digit', timeZone: 'Asia/Bangkok' }) : 'ทั้งวัน';
      return `${i+1}. ${datePart} ${timePart} — ${e.summary || '(ไม่มีหัวข้อ)'}`;
    } else {
      const time = e.start.dateTime ? d.toLocaleTimeString('th-TH', {hour:'2-digit',minute:'2-digit',timeZone:'Asia/Bangkok'}) : 'ทั้งวัน';
      return `${i+1}. ${time} — ${e.summary || '(ไม่มีหัวข้อ)'}`;
    }
  });
  text = `กิจกรรม${label} ${p.queryDate}:\n${lines.join('\n')}`;
}
return [{ json: { actionResult: text, replyToken: p.replyToken, intent: 'list' } }];

const events = $input.all().map(i => i.json).filter(j => j && j.id);
const p = $('Extract Parser JSON').first().json;
const tag = `[LINE:${p.userId}]`;
const kw = String(p.originalTitle || '').trim().toLowerCase();
const queryDate = p.queryDate || '';

let userEvents = events.filter(e => String(e.description || '').includes(tag));

if (queryDate) {
  userEvents = userEvents.filter(e => {
    const d = (e.start?.dateTime || e.start?.date || '').substring(0, 10);
    return d.startsWith(queryDate);
  });
}

if (userEvents.length === 0) {
  return [{ json: { canProceed: false, actionResult: `ไม่พบกิจกรรมในช่วง ${queryDate} ของคุณ`, replyToken: p.replyToken, intent: 'update' }}];
}

let matches = userEvents;
if (kw) matches = matches.filter(e => String(e.summary || '').toLowerCase().includes(kw));

if (matches.length === 0) {
  const list = userEvents.map((e, i) => {
    const t = e.start?.dateTime ? new Date(e.start.dateTime).toLocaleTimeString('th-TH', {hour:'2-digit', minute:'2-digit', timeZone:'Asia/Bangkok'}) : 'ทั้งวัน';
    return `${i+1}. ${t} — ${e.summary || '(ไม่มีหัวข้อ)'}`;
  }).join('\n');
  return [{ json: { canProceed: false, actionResult: `ไม่พบ "${p.originalTitle}" ในช่วง ${queryDate}\n\nกิจกรรมที่มี:\n${list}`, replyToken: p.replyToken, intent: 'update' }}];
}

if (matches.length > 1) {
  const list = matches.map((e, i) => {
    const t = e.start?.dateTime ? new Date(e.start.dateTime).toLocaleTimeString('th-TH', {hour:'2-digit', minute:'2-digit', timeZone:'Asia/Bangkok'}) : 'ทั้งวัน';
    return `${i+1}. ${t} — ${e.summary}`;
  }).join('\n');
  return [{ json: { canProceed: false, actionResult: `พบหลายรายการ ระบุให้ชัดกว่านี้:\n${list}`, replyToken: p.replyToken, intent: 'update' }}];
}

const e = matches[0];
const newTitle = p.changeTitle ? p.title : (e.summary || '');
const newStart = p.changeTime ? p.startDateTime : (e.start?.dateTime || e.start?.date);
const newEnd = p.changeTime ? p.endDateTime : (e.end?.dateTime || e.end?.date);

return [{ json: { canProceed: true, eventId: e.id, newTitle, newStart, newEnd, oldTitle: e.summary, replyToken: p.replyToken, intent: 'update' }}];

const u = $json;
const t = u.start?.dateTime ? new Date(u.start.dateTime).toLocaleString('th-TH', {dateStyle:'medium', timeStyle:'short', timeZone:'Asia/Bangkok'}) : 'ทั้งวัน';
return [{ json: { actionResult: `อัปเดต event "${u.summary}" เวลา ${t} เรียบร้อย`, replyToken: $('Find Match (Update)').first().json.replyToken, intent: 'update' }}];

const events = $input.all().map(i => i.json).filter(j => j && j.id);
const p = $('Extract Parser JSON').first().json;
const tag = `[LINE:${p.userId}]`;
const kw = String(p.originalTitle || '').trim().toLowerCase();
const queryDate = p.queryDate || '';

let userEvents = events.filter(e => String(e.description || '').includes(tag));

if (queryDate) {
  userEvents = userEvents.filter(e => {
    const d = (e.start?.dateTime || e.start?.date || '').substring(0, 10);
    return d.startsWith(queryDate);
  });
}

if (userEvents.length === 0) {
  return [{ json: { canProceed: false, actionResult: `ไม่พบกิจกรรมในช่วง ${queryDate} ไม่มีอะไรให้ลบ`, replyToken: p.replyToken, intent: 'delete' }}];
}

let matches = userEvents;
if (kw) matches = matches.filter(e => String(e.summary || '').toLowerCase().includes(kw));

if (matches.length === 0) {
  const list = userEvents.map((e, i) => {
    const t = e.start?.dateTime ? new Date(e.start.dateTime).toLocaleTimeString('th-TH', {hour:'2-digit', minute:'2-digit', timeZone:'Asia/Bangkok'}) : 'ทั้งวัน';
    return `${i+1}. ${t} — ${e.summary || '(ไม่มีหัวข้อ)'}`;
  }).join('\n');
  return [{ json: { canProceed: false, actionResult: `ไม่พบ "${p.originalTitle}"\n\nกิจกรรมที่มี:\n${list}`, replyToken: p.replyToken, intent: 'delete' }}];
}

const m = matches[0];
const t = m.start?.dateTime ? new Date(m.start.dateTime).toLocaleString('th-TH', {dateStyle:'medium', timeStyle:'short', timeZone:'Asia/Bangkok'}) : 'ทั้งวัน';

return [{ json: { canProceed: true, eventId: m.id, deletedTitle: m.summary, deletedTime: t, multipleMatches: matches.length > 1, matchCount: matches.length, replyToken: p.replyToken, intent: 'delete' }}];

