Intent: {{ $json.intent }}

parameters.jsCode:
const p = $('Extract Parser JSON').first().json;
const rawItems = $input.all().map(i => i.json);

let holidays = [];
let errorText = '';

// HTTP Request node อาจคืน error เมื่อ continueOnFail = true
if (rawItems.length === 1 && rawItems[0]?.error) {
  errorText = String(rawItems[0].error.message || rawItems[0].error || 'ไม่สามารถอ่านปฏิทินวันหยุดได้');
}

// กรณี HTTP Request คืน items อยู่ใน json.items
if (rawItems.length === 1 && Array.isArray(rawItems[0].items)) {
  holidays = rawItems[0].items;
} else {
  holidays = rawItems.filter(j => j && (j.id || j.summary));
}

const isMonth = !!p.isMonthQuery;
const label = isMonth ? 'เดือน' : 'วันที่';

let text = '';

if (errorText) {
  text = `ไม่สามารถตรวจสอบวันหยุดได้ในขณะนี้\nสาเหตุ: ${errorText}\n\nกรุณาตรวจสอบว่า Google Calendar API เปิดใช้งานแล้ว และ Credential มีสิทธิ์ใช้งาน Calendar API`;
} else if (holidays.length === 0) {
  text = `ไม่พบวันหยุด${label} ${p.queryDate}`;
} else {
  const lines = holidays.map((e, i) => {
    const s = e.start?.dateTime || e.start?.date || '';
    let dateText = '(ไม่ทราบวันที่)';

    if (s) {
      // all-day event ของ Google ใช้รูปแบบ YYYY-MM-DD
      const [y, m, d] = s.substring(0, 10).split('-').map(Number);
      const dt = new Date(y, m - 1, d);
      dateText = dt.toLocaleDateString('th-TH', {
        day: '2-digit',
        month: 'short',
        year: 'numeric',
        timeZone: 'Asia/Bangkok'
      });
    }

    return `${i + 1}. ${dateText} — ${e.summary || '(ไม่มีชื่อวันหยุด)'}`;
  });

  text = `วันหยุด${label} ${p.queryDate}:\n${lines.join('\n')}`;
}

return [{
  json: {
    actionResult: text,
    replyToken: p.replyToken,
    intent: 'holiday'
  }
}];
